import 'package:flutter_test/flutter_test.dart'; import 'package:googlepro/features/session/state/session_bloc_state.dart'; void main() { group('SessionBlocState', () { test('SessionActive isActive is true', () { const state = SessionActive(sessionId: 's1', deviceId: 'd1', deviceName: 'Dev'); expect(state, isA<SessionBlocState>()); }); test('SessionIdle initial state', () { const state = SessionIdle(); expect(state, isA<SessionBlocState>()); }); test('SessionEnded has reason', () { const state = SessionEnded(reason: 'user ended'); expect(state.reason, 'user ended'); }); }); }